#include <string>
#include <vector>
#include <algorithm>
#include <cmath>
#include <iostream>

using namespace std;

class Solution {
public:
    long long solve(std::string s) {
        int n = s.length();
        int count0 = 0;
        int count1 = 0;
        for (char c : s) {
            if (c == '0') {
                count0++;
            } else {
                count1++;
            }
        }

        // Case 1: No swap
        // Max balanced substring length without swap.
        // This is the standard max subarray with zero sum problem on (1 for '0', -1 for '1') or vice versa.
        // However, since the total counts might not be equal, we look for the longest balanced substring.
        int max_len_no_swap = 0;
        vector<int> prefix_diff(n + 1, 0); // prefix_diff[i] = count0[0..i-1] - count1[0..i-1]
        for (int i = 0; i < n; ++i) {
            int val = (s[i] == '0' ? 1 : -1);
            prefix_diff[i + 1] = prefix_diff[i] + val;
        }

        // Map to store the first occurrence of each prefix difference value
        // key: prefix difference, value: index i
        vector<int> first_occurrence(2 * n + 1, -1); 
        for (int i = -n; i <= n; ++i) {
            first_occurrence[i + n] = -1;
        }

        // For a balanced substring s[i..j-1], the difference must be 0, 
        // meaning prefix_diff[j] == prefix_diff[i].
        first_occurrence[prefix_diff[0] + n] = 0;

        for (int j = 1; j <= n; ++j) {
            int diff = prefix_diff[j];
            if (first_occurrence[diff + n] != -1) {
                int i = first_occurrence[diff + n];
                max_len_no_swap = max(max_len_no_swap, j - i);
            } else {
                first_occurrence[diff + n] = j;
            }
        }


        // Case 2: One swap
        // We want to maximize the length L of a balanced substring s'[i..i+L-1] 
        // after at most one swap.

        // A balanced substring must have k zeros and k ones, total length 2k.
        // Let the original substring s[i..j-1] have c0 zeros and c1 ones. 
        // For it to become balanced after a swap, the swap must fix the imbalance.

        // The crucial observation is that the maximum possible balanced substring length is 2 * min(count0, count1) + 2 * delta,
        // where delta is the maximum imbalance we can fix using one swap.
        // Since we only have one swap, the maximum imbalance we can fix is 1. 
        // E.g., if we have 3 zeros and 2 ones, imbalance is 1 (3-2=1). 
        // If we swap a 0 outside the substring with a 1 inside, we change counts to 2 zeros, 3 ones (imbalance -1).
        // If we swap a 0 inside with a 1 outside, we change counts to 2 zeros, 3 ones (imbalance -1).
        // Wait, the swap can be *anywhere* in the string.

        // The problem boils down to: What is the maximum length 2k such that we can find a substring 
        // of length 2k that has exactly k zeros and k ones, potentially after one swap?

        // Let the original counts be C0 and C1.
        // If |C0 - C1| <= 2, it might be possible to make the entire string balanced (if |C0 - C1| = 2).
        // If |C0 - C1| > 2, we cannot make the entire string balanced.

        // If we can make the whole string balanced (i.e., |C0 - C1| <= 2), the answer is N.
        if (abs(count0 - count1) <= 2) {
            // If |C0 - C1| <= 2, we can potentially make the entire string balanced.
            // If |C0 - C1| == 0 or 1, no swap is needed for the whole string (or a single swap might not improve it).
            // If |C0 - C1| == 2, one swap of the excess character with a character of the opposite type (if available outside) 
            // or swapping two characters of the same type (if beneficial locally) could balance it.

            // Since we are looking for a *substring*, if |C0 - C1| is small, the maximum balanced substring length is likely N.
            // Example: "1110" (C0=1, C1=3). Swap 1 and 0 -> "0111". Max balanced substring: "01" (len 2). 
            // Wait, the goal is max *substring* length, not the whole string.

            // Let's stick to the structure: max length is achieved either with 0 swaps (calculated above) or 1 swap.

            // Maximum possible length is 2 * min(C0, C1) + 2 (if we can balance the remaining 2 characters).
            // Maximum possible length is bounded by 2 * min(C0, C1) + 2 if |C0 - C1| >= 2.
            // If we can achieve a substring of length L, it must have L/2 zeros and L/2 ones.

            // If we swap s[a] and s[b]:
            // 1. s[a] = s[b] (no change in counts). Max length is max_len_no_swap.
            // 2. s[a] != s[b].
            //    a. If a and b are outside the target substring, counts inside are unchanged. Max length is max_len_no_swap.
            //    b. If both are inside, e.g., s[a]=0, s[b]=1, swapping them keeps counts inside unchanged. Max length is max_len_no_swap.
            //    c. If one is inside and one is outside. Suppose s[a] is inside (0), s[b] is outside (1). Swapping changes the inside count from (c0, c1) to (c0-1, c1+1).
            //    d. If both are outside. Max length is max_len_no_swap.

            // The only way a swap *increases* the max length is if it changes the count ratio inside a specific segment
            // from being non-balanced to balanced, or from being less balanced than the current max, to being more balanced.

            // Since the target is a balanced substring of length 2k, it must have k zeros and k ones.
            // The maximum possible k is min(C0, C1) + 1 if |C0-C1| >= 2, or min(C0, C1) if |C0-C1| <= 1.
            // Maximum possible length is 2 * min(C0, C1) + 2 * min(1, |C0 - C1| - 1)? No, this is too complex.

            // Let's simplify the goal of one swap:
            // We want to find a substring [i, j-1] such that its original counts (c0, c1) are as close as possible,
            // and after swapping one character inside (say, 0->1) with one outside (1->0), the new counts (c0', c1') become equal.
            // This requires the original segment to be highly imbalanced, e.g., c0 = k+d, c1 = k. We need to change it to (k, k).
            // This requires changing d excess '0's to '1's. This is impossible with one swap that changes the contents of the substring.

            // The only way a swap helps is if the swap *itself* contributes to the balanced nature of the substring.
            // Swap s[a] and s[b]. Consider a substring S that contains exactly one of {a, b}.
            // E.g., s[a]=0 (inside), s[b]=1 (outside). Swap makes s'[a]=1, s'[b]=0.
            // Inside S: c0 decreases by 1, c1 increases by 1. If the original was (k+1, k), it becomes (k, k+1). Length 2k+1. Not balanced.
            // If the original was (k+2, k), it becomes (k+1, k+1). Length 2k+2. Balanced!

            // Target: Find substring S = s[i..j-1] with original counts (c0, c1) such that:
            // 1. |c0 - c1| = 2, say c0 = c1 + 2.
            // 2. There exists an index $a \in [i, j-1]$ such that $s[a] = '0'$, and an index $b \notin [i, j-1]$ such that $s[b] = '1'$.
            // 3. Swapping $s[a]$ and $s[b]$ makes the new counts $(c0-1, c1+1) = (c1+1, c1+1)$. Length $2c1+2$.

            // Target: Find substring S = s[i..j-1] with original counts (c0, c1) such that:
            // 1. |c0 - c1| = 2, say c1 = c0 + 2.
            // 2. There exists an index $a \in [i, j-1]$ such that $s[a] = '1'$, and an index $b \notin [i, j-1]$ such that $s[b] = '0'$.
            // 3. Swapping $s[a]$ and $s[b]$ makes the new counts $(c0+1, c1-1) = (c0+1, c0+1)$. Length $2c0+2$.

            // Since we iterate over all substrings in the brute force approach, we are checking all possibilities.
            // N is up to 10^5. O(N^2) is too slow. We must use prefix sums/difference.

            // Let $d[k] = (\text{count of '0' in } s[0..k-1]) - (\text{count of '1' in } s[0..k-1])$.
            // For substring $s[i..j-1]$, the difference is $D = d[j] - d[i]$.
            // Length $L = j-i$. Number of zeros $c0$, ones $c1$. $c0+c1=L$. $c0-c1=D$.
            // $c0 = (L+D)/2$, $c1 = (L-D)/2$.

            // Case 0 swaps: $D=0$. $L$ is max length where $d[j]=d[i]$. (Calculated as max_len_no_swap).

            // Case 1 swap: The swap effectively changes the difference $D$ of the substring by $\pm 2$.
            // If we swap $s[a]=0$ (inside) with $s[b]=1$ (outside).
            // Inside: $c0 \to c0-1, c1 \to c1+1$. New difference $D' = (c0-1) - (c1+1) = D - 2$.
            // We need $D'=0$, so original $D=2$.
            // We need $d[j] - d[i] = 2$, AND we need an external '1' to swap with an internal '0'.

            // If we swap $s[a]=1$ (inside) with $s[b]=0$ (outside).
            // Inside: $c0 \to c0+1, c1 \to c1-1$. New difference $D' = (c0+1) - (c1-1) = D + 2$.
            // We need $D'=0$, so original $D=-2$.
            // We need $d[j] - d[i] = -2$, AND we need an external '0' to swap with an internal '1'.

            // We maximize $L = j-i$ subject to:
            // 1. $d[j] - d[i] = 2$ (and feasibility of external swap)
            // 2. $d[j] - d[i] = -2$ (and feasibility of external swap)

            // Feasibility check:
            // For $d[j] - d[i] = 2$: We need at least one '0' in $s[i..j-1]$ (guaranteed if $D=2>0$) AND at least one '1' outside $s[i..j-1]$.
            // For $d[j] - d[i] = -2$: We need at least one '1' in $s[i..j-1]$ (guaranteed if $D=-2<0$) AND at least one '0' outside $s[i..j-1]$.

            // Precompute suffix counts for feasibility check.
            vector<int> suffix_0(n + 1, 0);
            vector<int> suffix_1(n + 1, 0);
            for (int i = n - 1; i >= 0; --i) {
