            int max_len_one_swap = 0;

            // Iterate over all pairs (i, j) such that j > i and |d[j] - d[i]| = 2. (O(N^2) - still too slow)

            // We must use the map/hashing technique again.
            // Store indices based on the prefix difference d[i].
            // map<int, vector<int>> indices; // d[i] -> list of indices i where d[i] = value

            // Since we are looking for max j-i, we only need the minimum i for a fixed d[i].

            // Re-initialize the map approach to track min index for each difference.
            vector<int> first_occurrence_map(2 * n + 1, -1);
            for (int i = -n; i <= n; ++i) {
                first_occurrence_map[i + n] = -1;
            }
            first_occurrence_map[d[0] + n] = 0; // d[0] = 0

            // Since we need feasibility, we cannot just use first_occurrence. We must check all pairs (i, j).
            // Given the constraints and the nature of the problem, there might be an $O(N)$ or $O(N \log N)$ solution.

            // Let's re-examine the conditions based on fixed d[j] and target d[i].
            // Target $d[i] = d[j] - 2$. We want minimum $i$ such that $d[i] = d[j] - 2$ AND feasibility holds.
            // Target $d[i] = d[j] + 2$. We want minimum $i$ such that $d[i] = d[j] + 2$ AND feasibility holds.

            // We need to iterate $j$ from 1 to $N$. For each $j$, we check $d[j]-2$ and $d[j]+2$.
            // We need to know the minimum index $i < j$ such that $d[i]$ matches, AND the swap is possible.

            // Feasibility of swapping 0->1 inside S[i..j-1] with 1 outside:
            // 1. $d[j]-d[i]=2$. (Requires $c0 > 0$, which is true if $d>0$)
            // 2. Need $\exists b \notin [i, j-1]$ such that $s[b]=1$.
            // Total 1s is $C1$. $c1 = (L-2)/2$. Outside 1s is $C1 - c1$. We need $C1 - c1 > 0$.

            // Feasibility of swapping 1->0 inside S[i..j-1] with 0 outside:
            // 1. $d[j]-d[i]=-2$. (Requires $c1 > 0$, which is true if $d<0$)
            // 2. Need $\exists b \notin [i, j-1]$ such that $s[b]=0$.
            // Total 0s is $C0$. $c0 = (L+2)/2$. Outside 0s is $C0 - c0$. We need $C0 - c0 > 0$.

